from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal, InvalidOperation
from enum import Enum
from typing import Final

MoneyInput = Decimal | int | str

_ZERO: Final[Decimal] = Decimal("0")
_ONE_HUNDRED: Final[Decimal] = Decimal("100")


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is invalid."""


class InvalidUnitPriceError(ShoppingCartError):
    """Raised when a unit price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when an item quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when a requested item is not in the cart."""


class UnitPriceConflictError(ShoppingCartError):
    """Raised when an existing product is added with a different unit price."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents one product entry in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Calculate this item's total before discounts."""
        return self.unit_price * Decimal(self.quantity)


class _DiscountKind(Enum):
    PERCENTAGE = "percentage"
    FLAT = "flat"


@dataclass(frozen=True, slots=True)
class _Discount:
    kind: _DiscountKind
    value: Decimal


class ShoppingCart:
    """Manage shopping cart items, discounts, and totals."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount: _Discount | None = None

    def add_item(
        self,
        product_name: str,
        unit_price: MoneyInput,
        quantity: int = 1,
    ) -> CartItem:
        """Add an item to the cart and return the resulting cart item."""
        normalized_product_name = self._normalize_product_name(product_name)
        normalized_unit_price = self._parse_non_negative_decimal(
            unit_price,
            "Unit price",
            InvalidUnitPriceError,
        )
        validated_quantity = self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_product_name)
        if existing_item is not None:
            if existing_item.unit_price != normalized_unit_price:
                raise UnitPriceConflictError(
                    f"Product '{normalized_product_name}' already exists with "
                    f"unit price {existing_item.unit_price}."
                )

            updated_item = replace(
                existing_item,
                quantity=existing_item.quantity + validated_quantity,
            )
            self._items[normalized_product_name] = updated_item
            return updated_item

        new_item = CartItem(
            product_name=normalized_product_name,
            unit_price=normalized_unit_price,
            quantity=validated_quantity,
        )
        self._items[normalized_product_name] = new_item
        return new_item

    def remove_item(self, product_name: str) -> CartItem:
        """Remove an item by product name and return the removed item."""
        normalized_product_name = self._normalize_product_name(product_name)
        existing_item = self._get_existing_item(normalized_product_name)
        del self._items[normalized_product_name]
        return existing_item

    def update_quantity(self, product_name: str, quantity: int) -> CartItem:
        """Update the quantity of an existing item and return the updated item."""
        normalized_product_name = self._normalize_product_name(product_name)
        existing_item = self._get_existing_item(normalized_product_name)
        validated_quantity = self._validate_quantity(quantity)

        updated_item = replace(existing_item, quantity=validated_quantity)
        self._items[normalized_product_name] = updated_item
        return updated_item

    def calculate_subtotal(self) -> Decimal:
        """Calculate the cart subtotal before discounts."""
        return sum(
            (item.line_total for item in self._items.values()),
            start=_ZERO,
        )

    def apply_percentage_discount(self, percentage: MoneyInput) -> None:
        """Apply a percentage discount from 0 through 100."""
        discount_percentage = self._parse_decimal(
            percentage,
            "Percentage discount",
            InvalidDiscountError,
        )

        if discount_percentage < _ZERO or discount_percentage > _ONE_HUNDRED:
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

        self._discount = _Discount(
            kind=_DiscountKind.PERCENTAGE,
            value=discount_percentage,
        )

    def apply_flat_discount(self, amount: MoneyInput) -> None:
        """Apply a flat discount amount."""
        discount_amount = self._parse_non_negative_decimal(
            amount,
            "Flat discount",
            InvalidDiscountError,
        )

        self._discount = _Discount(kind=_DiscountKind.FLAT, value=discount_amount)

    def clear_discount(self) -> None:
        """Remove any active discount from the cart."""
        self._discount = None

    def calculate_discount_amount(self) -> Decimal:
        """Calculate the active discount amount for the current subtotal."""
        return self._calculate_discount_amount(self.calculate_subtotal())

    def calculate_total(self) -> Decimal:
        """Calculate the final cart total after discounts."""
        subtotal = self.calculate_subtotal()
        discount_amount = self._calculate_discount_amount(subtotal)
        return subtotal - discount_amount

    def list_items(self) -> tuple[CartItem, ...]:
        """Return an immutable snapshot of all cart items."""
        return tuple(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _get_existing_item(self, product_name: str) -> CartItem:
        try:
            return self._items[product_name]
        except KeyError as error:
            raise ItemNotFoundError(
                f"Product '{product_name}' is not in the cart."
            ) from error

    @staticmethod
    def _normalize_product_name(product_name: str) -> str:
        if not isinstance(product_name, str):
            raise InvalidProductNameError("Product name must be a string.")

        normalized_product_name = product_name.strip()
        if not normalized_product_name:
            raise InvalidProductNameError(
                "Product name must contain at least one non-whitespace character."
            )

        return normalized_product_name

    @staticmethod
    def _validate_quantity(quantity: int) -> int:
        if isinstance(quantity, bool) or not isinstance(quantity, int):
            raise InvalidQuantityError("Quantity must be an integer.")

        if quantity <= 0:
            raise InvalidQuantityError(
                "Quantity must be greater than zero. Use remove_item() to remove a product."
            )

        return quantity

    @classmethod
    def _parse_non_negative_decimal(
        cls,
        value: MoneyInput,
        field_name: str,
        exception_type: type[ShoppingCartError],
    ) -> Decimal:
        decimal_value = cls._parse_decimal(value, field_name, exception_type)

        if decimal_value < _ZERO:
            raise exception_type(f"{field_name} must be greater than or equal to zero.")

        return decimal_value

    @staticmethod
    def _parse_decimal(
        value: MoneyInput,
        field_name: str,
        exception_type: type[ShoppingCartError],
    ) -> Decimal:
        if isinstance(value, bool):
            raise exception_type(f"{field_name} must be a valid decimal number.")

        try:
            if isinstance(value, Decimal):
                decimal_value = value
            elif isinstance(value, int):
                decimal_value = Decimal(value)
            elif isinstance(value, str):
                decimal_value = Decimal(value.strip())
            else:
                raise exception_type(
                    f"{field_name} must be a Decimal, integer, or numeric string."
                )
        except (InvalidOperation, ValueError) as error:
            raise exception_type(
                f"{field_name} must be a valid decimal number."
            ) from error

        if not decimal_value.is_finite():
            raise exception_type(f"{field_name} must be a finite decimal number.")

        return decimal_value

    def _calculate_discount_amount(self, subtotal: Decimal) -> Decimal:
        if self._discount is None or subtotal <= _ZERO:
            return _ZERO

        if self._discount.kind is _DiscountKind.PERCENTAGE:
            discount_amount = subtotal * (self._discount.value / _ONE_HUNDRED)
        else:
            discount_amount = self._discount.value

        return min(discount_amount, subtotal)
